// Clothing exemptions vary by state — approximate per-item rules (verify against current law before relying on them).
// full: fully exempt · cap: only the amount over $cap per item is taxable · itemCap: item exempt only if priced under $itemCap.
const CLOTHING_RULE = { PA: { full: true }, NJ: { full: true }, MN: { full: true }, VT: { full: true }, MA: { cap: 175 }, RI: { cap: 250 }, NY: { itemCap: 110 } };
const clothingTaxableBase = (state, price) => {
  const r = CLOTHING_RULE[state];
  if (!r) return price;
  if (r.full) return 0;
  if (r.cap != null) return Math.max(0, price - r.cap);
  if (r.itemCap != null) return price < r.itemCap ? 0 : price;
  return price;
};
// Groceries: most states exempt unprepared food; a few tax it at a reduced flat rate, a few at the general rate.
// Prescription drugs: exempt almost everywhere (IL is the notable 1% exception). All figures approximate
// (~2024–25; grocery rules change often) and meant to be replaced by a tax API — verify before relying.
const GROCERY_REDUCED = { AR: 0.00125, IL: 0.01, MO: 0.01225, TN: 0.04, UT: 0.03, VA: 0.025 }; // flat combined rate on groceries
const GROCERY_TAXED = new Set(["HI", "ID", "MS", "SD", "AL"]); // groceries taxed at the general rate
const RX_REDUCED = { IL: 0.01 }; // prescription drugs taxed (else exempt)
// Tax for `price` of category `rule` at location `o` (carries stateRate/surtax/cap/state). Returns the
// effective rate to display plus the computed tax; states absent from a rule fall through to the general rate.
function categoryTax(rule, o, price) {
  const general = () => { const sb = o.cap ? Math.min(price, o.cap) : price; return { tax: price * o.stateRate + sb * o.surtax, taxBase: price, fullyExempt: false, rate: o.stateRate + o.surtax, note: null }; };
  if (!rule) return general();
  if (rule === "clothing") {
    const base = clothingTaxableBase(o.state, price);
    if (base === 0) return { tax: 0, taxBase: 0, fullyExempt: true, rate: 0, note: null };
    const sb = o.cap ? Math.min(base, o.cap) : base;
    return { tax: base * o.stateRate + sb * o.surtax, taxBase: base, fullyExempt: false, rate: o.stateRate + o.surtax, note: base < price ? "clothing" : null };
  }
  if (rule === "grocery") {
    if (GROCERY_TAXED.has(o.state)) return general();
    const red = GROCERY_REDUCED[o.state];
    if (red != null) return { tax: price * red, taxBase: price, fullyExempt: false, rate: red, note: "groceries" };
    return { tax: 0, taxBase: 0, fullyExempt: true, rate: 0, note: null };
  }
  if (rule === "rx") {
    const red = RX_REDUCED[o.state];
    if (red != null) return { tax: price * red, taxBase: price, fullyExempt: false, rate: red, note: "Rx" };
    return { tax: 0, taxBase: 0, fullyExempt: true, rate: 0, note: null };
  }
  return general();
}

