const AVG_SPEED = 50, MI = 69, R_EARTH = 3958.8;
const money = (n) => "$" + n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const money0 = (n) => "$" + Math.round(n).toLocaleString("en-US");
const pct = (r) => (r * 100).toFixed((r * 100) % 1 === 0 ? 0 : 2) + "%";
const haversine = (a, b) => {
  const t = (d) => (d * Math.PI) / 180, dLat = t(b.lat - a.lat), dLng = t(b.lng - a.lng);
  const x = Math.sin(dLat / 2) ** 2 + Math.cos(t(a.lat)) * Math.cos(t(b.lat)) * Math.sin(dLng / 2) ** 2;
  return R_EARTH * 2 * Math.atan2(Math.sqrt(x), Math.sqrt(1 - x));
};
function rateFor(geo) {
  if (!geo) return null;
  const st = geo.state;
  if (NOMAD.has(st)) return { stateRate: 0, surtax: 0, cap: null, precise: true, note: "no sales tax" };
  if (st === "FL") { const ci = FLZ[geo.zip]; if (ci != null) { const c = FLC[ci]; return { stateRate: 0.06, surtax: c[1], cap: 5000, precise: true, note: c[0] + " Co." }; } }
  const est = combinedFor(st);
  if (est == null) return { stateRate: 0, surtax: 0, cap: null, precise: false, note: "rate unknown — connect tax API" };
  return { stateRate: est, surtax: 0, cap: null, precise: false, note: "est. combined (state + avg local)" };
}
function resolveZip(zip) {
  const z = (zip || "").trim();
  if (!/^\d{5}$/.test(z)) return null;
  const ex = ZIP_FALLBACK[z];
  if (ex) return { zip: z, city: ex.city, state: ex.state, lat: ex.lat, lng: ex.lng, county: ex.county, label: `${ex.city}, ${ex.state}`, precision: "exact" };
  const p = ZIP3[z.slice(0, 3)];
  if (p) {
    const st = p[2];
    const lbl = (st === "FL" && FLZ[z] != null) ? `${z} \u00b7 ${FLC[FLZ[z]][0]} Co., FL` : `${z} \u00b7 ${st}`;
    return { zip: z, city: null, state: st, lat: p[0], lng: p[1], county: undefined, label: lbl, precision: "approx" };
  }
  return null;
}

